class Solution:
    def nextBeautifulNumber(self, n: int) -> int:
        def is_beautiful(num):
            num_str = str(num)
            for digit in num_str:
                if int(digit) != int(digit) * (num_str.count(digit)):
                    return False
            return True

        n += 1
        while not is_beautiful(n):
            n += 1
        return n
